var minOperations = function(nums, k) {
    // Min-heap
    const h = [...nums];
    const swap = (i, j) => { [h[i], h[j]] = [h[j], h[i]]; };
    const siftDown = (i) => {
        while (true) {
            let s = i, l = 2*i+1, r = 2*i+2;
            if (l < h.length && h[l] < h[s]) s = l;
            if (r < h.length && h[r] < h[s]) s = r;
            if (s === i) break;
            swap(i, s); i = s;
        }
    };
    // Heapify
    for (let i = Math.floor(h.length / 2) - 1; i >= 0; i--) siftDown(i);
    const pop = () => {
        const top = h[0];
        h[0] = h[h.length - 1]; h.pop(); siftDown(0);
        return top;
    };
    const push = (v) => {
        h.push(v);
        let i = h.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (h[p] <= h[i]) break;
            swap(p, i); i = p;
        }
    };
    let ops = 0;
    while (h[0] < k) {
        const x = pop(), y = pop();
        push(Math.min(x, y) * 2 + Math.max(x, y));
        ops++;
    }
    return ops;
};
